export type Product = {
  id: number;
  sku: string;
  name: string;
  price: number;
  inventory: number;
  availability: string;
};

const sleep = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

let products: Product[] = [
  { id: 1, sku: 'LAP-001', name: 'Laptop', price: 999, inventory: 12, availability: 'In stock' },
  { id: 2, sku: 'PHN-002', name: 'Phone', price: 699, inventory: 25, availability: 'In stock' },
  { id: 3, sku: 'TAB-003', name: 'Tablet', price: 499, inventory: 8, availability: 'Low stock' },
  { id: 4, sku: 'HDP-004', name: 'Headphones', price: 199, inventory: 0, availability: 'Backorder' },
  { id: 5, sku: 'WTC-005', name: 'Watch', price: 299, inventory: 17, availability: 'In stock' }
];

function cloneProducts(items: Product[]) {
  return items.map((product) => ({ ...product }));
}

function getAvailability(inventory: number) {
  if (inventory === 0) return 'Backorder';
  if (inventory < 10) return 'Low stock';
  return 'In stock';
}

async function readProductsFromSource() {
  await sleep(100);
  return cloneProducts(products);
}

const getCachedProducts = unstable_cache(readProductsFromSource, ['products-catalog'], {
  tags: ['products']
});

export async function getAllProducts() {
  return getCachedProducts();
}

export async function syncLatestCatalog() {
  setTimeout(() => {
    products = products.map((product) => {
      const inventory = Math.max(0, product.inventory + (product.id % 2 === 0 ? 4 : -2));

      return {
        ...product,
        price: product.price + 10,
        inventory,
        availability: getAvailability(inventory)
      };
    });

    revalidateTag('products', 'max');
  }, 0);
}
