  const products = await getAllProducts();

  return (
    <main style={{ padding: '2rem', fontFamily: 'Arial, sans-serif' }}>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'start',
          gap: '1rem',
          marginBottom: '2rem'
        }}
      >
        <div>
          <h1 style={{ margin: 0 }}>Admin product catalog</h1>
          <p style={{ marginTop: '0.5rem', color: '#555', maxWidth: 720 }}>
            Browse the cached catalog snapshot for fast day-to-day admin work. When ERP/PIM data changes,
            trigger a background sync and keep working while shared catalog views become fresh shortly after.
          </p>
        </div>

        <form
          action={async () => {
            'use server';
            await syncLatestCatalog();
          }}
        >
          <button
            type="submit"
            style={{
              border: 'none',
              borderRadius: 8,
              background: '#111827',
              color: 'white',
              padding: '0.75rem 1rem',
              fontWeight: 600,
              cursor: 'pointer'
