              <td style={{ padding: '0.75rem' }}>${product.price}</td>
              <td style={{ padding: '0.75rem' }}>{product.inventory}</td>
              <td style={{ padding: '0.75rem' }}>{product.availability}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </main>
  );
}
